// CLI Interface
// ============================================================

function printUsage() {
  console.log(`
╔══════════════════════════════════════════════════════════════╗
║              Package Lock Manager - CLI                      ║
╠══════════════════════════════════════════════════════════════╣
║                                                              ║
║  Usage: node package-lock-manager.js <command> [options]     ║
║                                                              ║
║  Commands:                                                   ║
║    generate        Generate/regenerate package-lock.json     ║
║    validate        Validate lock file integrity              ║
║    install-ci      Install from lock file (CI mode)          ║
║    update [pkgs]   Update dependencies                       ║
║    audit           Run security audit                        ║
║    report          Generate dependency report                ║
║    docs            Generate team documentation               ║
║    ci-configs      Generate CI/CD configuration files        ║
║    verify-sync     Verify lock file is in sync               ║
║    backup          Backup current lock file                  ║
║    info            Show lock file information                ║
║    pre-commit-hook Print pre-commit hook script              ║
║    help            Show this help message                    ║
║                                                              ║
║  Options:                                                    ║
║    --clean         Clean install (remove node_modules)       ║
║    --production    Production mode (omit devDependencies)    ║
║    --dry-run       Show what would change without applying   ║
║    --fix           Auto-fix (for audit command)              ║
║                                                              ║
╚══════════════════════════════════════════════════════════════╝
  `);
}

function main() {
  const args = process.argv.slice(2);
  const command = args[0];
  const flags = args.slice(1);

  const manager = new PackageLockManager();

  const hasFlag = (flag) => flags.includes(`--${flag}`);

  try {
    switch (command) {
      case 'generate':
        manager.generateLockFile({
          clean: hasFlag('clean')
        });
        break;

      case 'validate':
        const validation = manager.validateLockFile();
        console.log('\n=== Lock File Validation ===\n');
        console.log(`Status: ${validation.valid ? '✅ Valid' : '❌ Invalid'}`);
        if (validation.errors.length > 0) {
          console.log('\nErrors:');
          validation.errors.forEach(e => console.log(`  ❌ ${e}`));
        }
        if (validation.warnings.length > 0) {
          console.log('\nWarnings:');
          validation.warnings.forEach(w => console.log(`  ⚠️  ${w}`));
        }
        console.log('\nInfo:', JSON.stringify(validation.info, null, 2));
        if (!validation.valid) process.exit(1);
        break;

      case 'install-ci':
        manager.installFromLockFile({
          production: hasFlag('production')
        });
        break;

      case 'update':
        const packages = flags.filter(f => !f.startsWith('--'));
        manager.updateDependencies(packages, {
          dryRun: hasFlag('dry-run')
        });
        break;

      case 'audit':
        manager.auditDependencies({
          fix: hasFlag('fix'),
          production: hasFlag('production')
        });
        break;

      case 'report':
        manager.generateReport();
        break;

      case 'docs':
        manager.writeDocumentation();
        break;

      case 'ci-configs':
        manager.writeCIConfigs();
        break;

      case 'verify-sync':
        const syncResult = manager.verifyLockFileSync();
        if (!syncResult.inSync) process.exit(1);
        break;

      case 'backup':
        manager.backupLockFile('manual');
        break;

      case 'info':
        const info = manager.getLockFileInfo();
        console.log('\n=== Lock File Information ===\n');
        console.log(JSON.stringify(info, null, 2));
        break;

      case 'pre-commit-hook':
        console.log(manager.generatePreCommitHook());
        break;

      case 'help':
      case '--help':
      case '-h':
      case undefined:
        printUsage();
        break;

      default:
        console.error(`Unknown command: ${command}`);
        printUsage();
        process.exit(1);
    }
  } catch (error) {
    console.error(`\n💥 Error: ${error.message}`);
    process.exit(1);
  }
}

// Run CLI if executed directly
if (require.main === module) {
  main();
}

// Export for programmatic use
module.exports = PackageLockManager;